sqlMap.select:
SELECT A.ID, A.TITLE FROM tbl_vote_question A JOIN tbl_vote_user_and_question B ON A.ID = B.QST_ID AND A.TENANT_ID = B.TENANT_ID WHERE A.END_DATE > date_format(now(), '%Y-%m-%d %H:%i:%s') AND ( ( B.USER_ID = #userId# AND B.user_type = 'user' ) OR ( B.USER_type = 'company' AND B.USER_ID = #companyId# ) OR ( B.user_type = 'dept' AND B.USER_ID IN ( SELECT C.CN FROM TBL_DEPTMASTER C WHERE (FIND_IN_SET (CN, #deptPath#) OR CN = 'Top') AND C.TENANT_ID = #tenantId# ) )
OR A.COMPANYID = #companyId#
) AND a.TENANT_ID = #tenantId# ORDER BY CREATE_DATE DESC LIMIT 1

